CREATE OR REPLACE FUNCTION trigger_function() RETURNS TRIGGER AS $BODY$
BEGIN
    INSERT INTO public.destination_table (
        created_at,
        match_id,
        player_id,
        event_type,
        url,
        user_id
    )
    VALUES (
        NEW.created_at,
        NEW.match_id,
        NEW.player_id,
        NEW.event_type,
        split_part(NEW.url::text, '?', 1),
        (NEW.data -> 'local_storage' -> 'data' ->> 'user_id')::varchar
    );
    RETURN NEW;
END;
$BODY$ LANGUAGE plpgsql;

