-- Drop existing aggregate and function if they exist
DROP AGGREGATE IF EXISTS GapFill(anyelement);
DROP FUNCTION IF EXISTS GapFillInternal(anyelement, anyelement);

-- Create the internal state transition function
CREATE OR REPLACE FUNCTION GapFillInternal(s anyelement, v anyelement)
RETURNS anyelement AS $$
BEGIN
    IF v IS NOT NULL THEN
        RETURN v;
    ELSE
        RETURN s;
    END IF;
END;
$$ LANGUAGE PLPGSQL;

-- Create the aggregate function
CREATE AGGREGATE GapFill(anyelement) (
    SFUNC = GapFillInternal,
    STYPE = anyelement
);

-- Query on superhero table with forward fill on height_cm and weight_kg
SELECT
    id,
    publisher_id,
    height_cm,
    weight_kg,
    GapFill(height_cm) OVER (PARTITION BY publisher_id ORDER BY id) AS height_cm_filled,
    GapFill(weight_kg) OVER (PARTITION BY publisher_id ORDER BY id) AS weight_kg_filled
FROM superhero

