CREATE OR REPLACE FUNCTION reindex_superhero_ids(IN BIGINT) RETURNS VOID LANGUAGE plpgsql AS $$
BEGIN
    -- Drop the temporary sequence if it already exists from a previous call
    DROP SEQUENCE IF EXISTS id_seq_temp;

    CREATE TEMPORARY SEQUENCE id_seq_temp MINVALUE 1 START WITH 1 INCREMENT BY 1;

    -- Shift hair_colour_ids to avoid conflicts during reindexing
    UPDATE superhero SET hair_colour_id = hair_colour_id + 2000 WHERE publisher_id = $1;

    -- Assign new contiguous hair_colour_ids using the temporary sequence
    UPDATE superhero SET hair_colour_id = nextval('id_seq_temp') WHERE publisher_id = $1;

    -- Clean up the temporary sequence
    DROP SEQUENCE id_seq_temp;
END;
$$
